import{_ as r,E as o,c as h,J as l,w as i,V as e,o as s,m as t}from"./chunks/framework.vTT8XiEL.js";const N=JSON.parse('{"title":"视野修炼第22期","description":"① 纯CSS实现树状视图 ② 为什么JSON中不支持注释 ③ 漫画HTTPS工作原理 ④ 🎉Github有1亿开发者了 ...","frontmatter":{"description":"① 纯CSS实现树状视图 ② 为什么JSON中不支持注释 ③ 漫画HTTPS工作原理 ④ 🎉Github有1亿开发者了 ...","hidden":true},"headers":[],"relativePath":"weekly/2023-01-26.md","filePath":"weekly/2023-01-26.md","lastUpdated":1675386771000}'),n={name:"weekly/2023-01-26.md"},p=e('<h1 id="视野修炼第22期" tabindex="-1">视野修炼第22期 <a class="header-anchor" href="#视野修炼第22期" aria-label="Permalink to &quot;视野修炼第22期&quot;">​</a></h1><blockquote><p>假期就要结束了，相信部分朋友已经开始上班了。</p></blockquote><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDY2MzI3MTg2OQ==674663271869" alt="图片"></p><p>欢迎来到第 22 期的【视野修炼 - 技术周刊】，下面是本期的精选内容简介。</p><nav class="table-of-contents"><ul><li><a href="#🔥强烈推荐">🔥强烈推荐</a><ul><li><a href="#_1-英-纯css实现树状视图">1. 英：纯CSS实现树状视图</a></li><li><a href="#_2-为什么json中不支持注释">2. 为什么JSON中不支持注释</a></li><li><a href="#_3-漫画-https-的工作原理">3. 漫画：HTTPS 的工作原理</a></li><li><a href="#_4-🎉github有1亿开发者了">4. 🎉Github有1亿开发者了</a></li></ul></li><li><a href="#🔧开源-工具">🔧开源&amp;工具</a><ul><li><a href="#_5-blurhash-模糊图生成">5. blurhash - 模糊图生成</a></li><li><a href="#_6-zod-数据校验">6. zod - 数据校验</a></li><li><a href="#_7-github520">7. GitHub520</a></li></ul></li><li><a href="#📚文章-资讯">📚文章&amp;资讯</a><ul><li><a href="#_8-bun-v0-5">8. Bun v0.5</a></li><li><a href="#_9-typescript-5-0-beta">9. TypeScript 5.0 Beta</a></li></ul></li><li><a href="#⭐️强力推荐关注">⭐️强力推荐关注</a></li></ul></nav>',5),c=t("p",null,[t("strong",null,"​也推荐大家关注一下最后的推荐内容（周刊的主要内容来源渠道）")],-1),u=e('<p>下面开始本期内容的介绍<strong>ღ( ´･ᴗ･` )比心</strong>。</p><h2 id="🔥强烈推荐" tabindex="-1">🔥强烈推荐 <a class="header-anchor" href="#🔥强烈推荐" aria-label="Permalink to &quot;🔥强烈推荐&quot;">​</a></h2><h3 id="_1-英-纯css实现树状视图" tabindex="-1"><a href="https://iamkate.com/code/tree-views/" target="_blank" rel="noreferrer">1. 英：纯CSS实现树状视图</a> <a class="header-anchor" href="#_1-英-纯css实现树状视图" aria-label="Permalink to &quot;[1. 英：纯CSS实现树状视图](https://iamkate.com/code/tree-views/)&quot;">​</a></h3><p>利用<code>ul</code>,<code>li</code>,<code>details</code>,<code>summary</code>4个标签实现</p><p>其中<code>summary</code>，可以通过<code>open</code>属性控制显隐状态</p><p>下面是个最简示例</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDc4NzM4NDQxNA==674787384414" alt="图片"></p><p>文章里还额外介绍了一些css样式的属性，最终效果如下</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDc4NzkyMzM3MA==674787923370" alt="图片"></p><h3 id="_2-为什么json中不支持注释" tabindex="-1"><a href="https://www.stefanjudis.com/notes/why-doesnt-json-support-comments/" target="_blank" rel="noreferrer">2. 为什么JSON中不支持注释</a> <a class="header-anchor" href="#_2-为什么json中不支持注释" aria-label="Permalink to &quot;[2. 为什么JSON中不支持注释](https://www.stefanjudis.com/notes/why-doesnt-json-support-comments/)&quot;">​</a></h3><p>这个疑问相信大家在接触JSON的时候都遇到过，实际上在<code>最初的规范里JSON是允许注释的</code></p><p>文章大概阐述了3点原因如下（机翻）</p><ul><li>注释中被放入了解析指令，破坏了跨平台的移植性</li><li>注释引入了可能不需要的数据格式的复杂性</li><li>JSON的创造者希望它能与早期YAML版本兼容</li></ul><h3 id="_3-漫画-https-的工作原理" tabindex="-1"><a href="https://howhttps.works/zh/" target="_blank" rel="noreferrer">3. 漫画：HTTPS 的工作原理</a> <a class="header-anchor" href="#_3-漫画-https-的工作原理" aria-label="Permalink to &quot;[3. 漫画：HTTPS 的工作原理](https://howhttps.works/zh/)&quot;">​</a></h3><p>非常有意思的讲解<code>HTTPS</code>相关知识，推荐对HTTPS不那么熟悉的可以闲暇的时候阅读一下</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDg3ODA5Njg2NA==674878096864" alt="图片"></p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDg3NzgyOTAxNQ==674877829016" alt="图片"></p><h3 id="_4-🎉github有1亿开发者了" tabindex="-1"><a href="https://github.blog/2023-01-25-100-million-developers-and-counting/" target="_blank" rel="noreferrer">4. 🎉Github有1亿开发者了</a> <a class="header-anchor" href="#_4-🎉github有1亿开发者了" aria-label="Permalink to &quot;[4. 🎉Github有1亿开发者了](https://github.blog/2023-01-25-100-million-developers-and-counting/)&quot;">​</a></h3><p>今天你在访问<a href="https://github.com/ATQQ" target="_blank" rel="noreferrer">Github个人主页</a>时会看到一个如下所示的带动画的消息入口。</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDg5NTIzOTk2MQ==674895239961" alt="图片"></p><p>2019年设定的目标，<a href="https://youtu.be/9EoNqyxtSRM?t=344" target="_blank" rel="noreferrer">到2025年使用人数达到1亿</a>，比原计划提前了2年。</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDg5MzU2NDUwNA==674893564504" alt="图片"></p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDg5MzgzNTAxMQ==674893835011" alt="图片"></p><p>越来越多的开发者了解并使用Github，意味着有越来越多的人了解到开源，参与开源，共同建设技术社区。</p><h2 id="🔧开源-工具" tabindex="-1">🔧开源&amp;工具 <a class="header-anchor" href="#🔧开源-工具" aria-label="Permalink to &quot;🔧开源&amp;工具&quot;">​</a></h2><h3 id="_5-blurhash-模糊图生成" tabindex="-1"><a href="https://github.com/woltapp/blurhash" target="_blank" rel="noreferrer">5. blurhash</a> - 模糊图生成 <a class="header-anchor" href="#_5-blurhash-模糊图生成" aria-label="Permalink to &quot;[5. blurhash](https://github.com/woltapp/blurhash) - 模糊图生成&quot;">​</a></h3><p>这个工具可以提取图片的颜色分布，生成一个哈希字符串。网页就可以用这个哈希，生成图片的模糊缩略图</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDc4OTM3MDk4MQ==674789370981" alt="图片"></p><h3 id="_6-zod-数据校验" tabindex="-1"><a href="https://github.com/colinhacks/zod" target="_blank" rel="noreferrer">6. zod</a> - 数据校验 <a class="header-anchor" href="#_6-zod-数据校验" aria-label="Permalink to &quot;[6. zod](https://github.com/colinhacks/zod) - 数据校验&quot;">​</a></h3><p>支持<code>TS（静态类型检查）</code>与<code>js（运行时检查）</code></p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDc5MTQ5MjU0OA==674791492548" alt="图片"></p><p>这篇文章 <a href="https://dev.to/jareechang/zod-the-next-biggest-thing-after-typescript-4phh" target="_blank" rel="noreferrer">Zod: The Next Biggest thing after Typescript</a> 阐述了使用其的优势</p><h3 id="_7-github520" tabindex="-1"><a href="https://github.com/521xueweihan/GitHub520" target="_blank" rel="noreferrer">7. GitHub520</a> <a class="header-anchor" href="#_7-github520" aria-label="Permalink to &quot;[7. GitHub520](https://github.com/521xueweihan/GitHub520)&quot;">​</a></h3><p>对于没有梯子（科学上网工具）的朋友，遇到访问Github慢或者图裂的问题，通常手段都是改hosts</p><p>下面的地址即这个项目提供的链接，无需访问 GitHub 即可获取到最新的 hosts 内容：</p><ul><li>文件：<a href="https://raw.hellogithub.com/hosts" target="_blank" rel="noreferrer">https://raw.hellogithub.com/hosts</a></li><li>JSON：<a href="https://raw.hellogithub.com/hosts.json" target="_blank" rel="noreferrer">https://raw.hellogithub.com/hosts.json</a></li></ul><p>当然项目里也提供了自动配置更新的方式</p><h2 id="📚文章-资讯" tabindex="-1">📚文章&amp;资讯 <a class="header-anchor" href="#📚文章-资讯" aria-label="Permalink to &quot;📚文章&amp;资讯&quot;">​</a></h2><h3 id="_8-bun-v0-5" tabindex="-1"><a href="https://bun.sh/blog/bun-v0.5.0" target="_blank" rel="noreferrer">8. Bun v0.5</a> <a class="header-anchor" href="#_8-bun-v0-5" aria-label="Permalink to &quot;[8. Bun v0.5](https://bun.sh/blog/bun-v0.5.0)&quot;">​</a></h3><p>支持<code>monorepo</code>，当然也是号称速度比其它的快</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY3NDc5MDQ5OTMzOQ==674790499339" alt="图片"></p><h3 id="_9-typescript-5-0-beta" tabindex="-1"><a href="https://devblogs.microsoft.com/typescript/announcing-typescript-5-0-beta/" target="_blank" rel="noreferrer">9. TypeScript 5.0 Beta</a> <a class="header-anchor" href="#_9-typescript-5-0-beta" aria-label="Permalink to &quot;[9. TypeScript 5.0 Beta](https://devblogs.microsoft.com/typescript/announcing-typescript-5-0-beta/)&quot;">​</a></h3><p>26号发布，带来了许多新的特性，其中最值得关注的就是 <a href="https://github.com/microsoft/TypeScript/pull/50820" target="_blank" rel="noreferrer">实现 Stage3 装饰器提案</a></p><hr><p>篇幅有限，如果你还没看够，可移步后面的推荐渠道，继续游览，历史周刊（&lt;20）<a href="https://sugarat.top/weekly/index.html" target="_blank" rel="noreferrer">移步博客</a></p><h2 id="⭐️强力推荐关注" tabindex="-1">⭐️强力推荐关注 <a class="header-anchor" href="#⭐️强力推荐关注" aria-label="Permalink to &quot;⭐️强力推荐关注&quot;">​</a></h2><ul><li><a href="https://www.ruanyifeng.com/blog/archives.html" target="_blank" rel="noreferrer">阮一峰: 科技爱好者周刊</a> - 记录每周值得分享的科技内容，周五发布</li><li><a href="https://www.yuque.com/chencheng/mdh-weekly" target="_blank" rel="noreferrer">云谦：MDH 前端周刊</a> - 前端资讯和分享</li><li><a href="https://github.com/Geekhyt/weekly" target="_blank" rel="noreferrer">童欧巴：前端食堂</a> - 你的前端食堂，吃好每一顿饭</li><li><a href="https://rottenpen.zhubai.love/" target="_blank" rel="noreferrer">rottenpen：FE News</a> - 分享前端，生活</li><li><a href="https://public.zsxq.com/groups/28851452458181.html" target="_blank" rel="noreferrer">知识星球：咲奈的平行时空</a> - 前端前沿技术、资讯、方法论分享</li></ul>',47);function d(g,b,m,_,f,k){const a=o("center");return s(),h("div",null,[p,l(a,null,{default:i(()=>[c]),_:1}),u])}const S=r(n,[["render",d]]);export{N as __pageData,S as default};
